pub fn extract_yaml(response: &str) -> Option<String> {
    // Try to find YAML in code fence first
    let fence_pattern = "```yaml";
    if let Some(start) = response.find(fence_pattern) {
        let start_pos = start + fence_pattern.len();
        if let Some(end) = response[start_pos..].find("```") {
            let yaml_content = &response[start_pos..start_pos + end];
            return Some(yaml_content.trim().to_string());
        }
    }

    // If no fence found, look for YAML starting with a key
    let lines: Vec<&str> = response.lines().collect();
    let mut yaml_lines = Vec::new();
    let mut in_yaml = false;

    for line in lines {
        if line.trim().is_empty() {
            continue;
        }

        if line.trim().chars().next().map_or(false, |c| c.is_alphabetic()) {
            // Found a line that starts with a letter, check if it's a YAML key
            if let Some(colon_pos) = line.find(':') {
                if colon_pos > 0 {
                    in_yaml = true;
                    yaml_lines.push(line);
                }
            } else {
                // No colon, not a YAML key
                if in_yaml {
                    break;
                }
            }
        } else if in_yaml {
            // Continue collecting lines until we hit a non-YAML line
            yaml_lines.push(line);
        }
    }

    if !yaml_lines.is_empty() {
        return Some(yaml_lines.join("\n").trim().to_string());
    }

    None
}
